object AuthPrefs {
    private const val PREFS = "auth_prefs"
    private const val KEY_AUTHENTICATED = "authenticated"
    private const val KEY_HAS_PASSWORD = "has_password"
    private const val KEY_PASSWORD = "password"

    fun prefs(context: Context): SharedPreferences =
        context.getSharedPreferences(PREFS, Context.MODE_PRIVATE)

    fun isAuthenticated(context: Context): Boolean =
        prefs(context).getBoolean(KEY_AUTHENTICATED, false)

    fun setAuthenticated(context: Context, authenticated: Boolean) {
        prefs(context).edit().putBoolean(KEY_AUTHENTICATED, authenticated).apply()
    }

    fun hasPassword(context: Context): Boolean =
        prefs(context).getBoolean(KEY_HAS_PASSWORD, false)

    fun ensureDefaultPassword(context: Context) {
        val p = prefs(context)
        if (!p.getBoolean(KEY_HAS_PASSWORD, false)) {
            p.edit()
                .putBoolean(KEY_HAS_PASSWORD, true)
                .putString(KEY_PASSWORD, "password")
                .apply()
        }
    }

    fun verifyPassword(context: Context, input: String): Boolean {
        val stored = prefs(context).getString(KEY_PASSWORD, null) ?: return false
        return stored == input
    }

    fun setPassword(context: Context, newPassword: String) {
        prefs(context).edit()
            .putBoolean(KEY_HAS_PASSWORD, true)
            .putString(KEY_PASSWORD, newPassword)
            .apply()
    }

    fun logout(context: Context) {
        setAuthenticated(context, false)
    }
}

class LoginActivity : ComponentActivity() {

