    private fun canUseBiometric(): Boolean {
        val manager = BiometricManager.from(this)
        val can = manager.canAuthenticate(BiometricManager.Authenticators.BIOMETRIC_STRONG)
        return can == BiometricManager.BIOMETRIC_SUCCESS
    }

